import sys

def main():
    N = int(sys.stdin.readline())
    result = [''] * (N + 1)

    # Find all divisors of N between 1 and 9
    divisors = []
    for j in range(1, 10):
        if N % j == 0:
            divisors.append(j)

    for i in range(N + 1):
        min_j = None
        for j in divisors:
            if i % (N // j) == 0:
                if min_j is None or j < min_j:
                    min_j = j
        if min_j is not None:
            result[i] = str(min_j)
        else:
            result[i] = '-'

    print(''.join(result))

if __name__ == "__main__":
    main()
